<script type="text/javascript" src="./assets/bootstrap/js/bootstrap.bundle.min.js"></script>
<script type="text/javascript" src="./assets/js/app.js"></script>

<link rel="stylesheet" href="./assets/libs/glide/css/glide.core.min.css">
<script src="./assets/libs/glide/glide.min.js"></script>

<script>
    function glideSlider() {
        return {
            glide: null,
            init() {
                this.glide = new Glide('.glide', {
                    type: 'carousel',
                    perView: 1,
                    autoplay: 5000,
                    hoverpause: true,
                    animationDuration: 700,
                });
                this.glide.mount();
            }
        }
    }

    function riskCounter() {
        const radius = 25;
        const circumference = 2 * Math.PI * radius;

        return {
            count: 54,
            min: 0,
            max: 100,
            radius,
            circumference,
            get dashOffset() {
                return this.circumference - (this.count / 100) * this.circumference;
            },
            increment() {
                if (this.count < this.max) this.count++;
            },
            decrement() {
                if (this.count > this.min) this.count--;
            }
        };
    }
</script>


<script type="text/javascript" src="./assets/js/alpinejs.min.js"></script>


